+        let ir = make_ir(2, &[(0, 1)]);
+        let laplacian = build_laplacian(&ir);
+
+        // L = [[1, -1], [-1, 1]] for a single edge
+        assert_eq!(laplacian[(0, 0)], 1.0);
+        assert_eq!(laplacian[(1, 1)], 1.0);
+        assert_eq!(laplacian[(0, 1)], -1.0);
+        assert_eq!(laplacian[(1, 0)], -1.0);
+    }
