+        let laplacian = build_laplacian(&ir);
+
+        for i in 0..5 {
+            let row_sum: f64 = (0..5).map(|j| laplacian[(i, j)]).sum();
+            assert!(row_sum.abs() < 1e-12, "Row {i} sum = {row_sum}, expected 0");
+        }
